<script>
let currentProjSubTab = 'b5';

function switchResearchTab(tab, btn) {
    document.querySelectorAll('.research-page-container > .int-tab-bar .int-tab-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    
    document.querySelectorAll('.research-page-container > .int-tab-panel').forEach(p => p.classList.remove('active'));
    document.getElementById('research-panel-' + tab).classList.add('active');
    
    // Smooth scroll to container offset by sticky header height
    const container = document.querySelector('.research-page-container');
    const headerHeight = document.querySelector('.site-header')?.offsetHeight || 90;
    const targetPos = container.getBoundingClientRect().top + window.pageYOffset - headerHeight - 16;
    window.scrollTo({ top: targetPos, behavior: 'smooth' });
}

function switchProjSubTab(subTab, btn) {
    document.querySelectorAll('#research-panel-projects .filter-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    
    document.querySelectorAll('.proj-sub-panel').forEach(p => p.classList.remove('active'));
    document.getElementById('proj-sub-' + subTab).classList.add('active');
    currentProjSubTab = subTab;
    filterProjects();
}

function filterProjects() {
    const query = document.getElementById('project-search').value.toLowerCase();
    const rows = document.querySelectorAll('.project-row');
    
    rows.forEach(row => {
        const isB5 = row.classList.contains('b5-proj');
        const isCorrectSubTab = (currentProjSubTab === 'b5' && isB5) || (currentProjSubTab === 'b10' && !isB5);
        const searchContent = row.dataset.searchContent;
        
        if (isCorrectSubTab && searchContent.includes(query)) {
            row.style.display = '';
        } else {
            row.style.display = 'none';
        }
    });
}
</script>

<style>
.proj-sub-panel {
    display: none;
}
.proj-sub-panel.active {
    display: block;
}
</style>
